def cherryPickup(grid):
    N = len(grid)
    dp = {}

    def solve(r1, c1, r2, c2):
        if (r1, c1, r2, c2) in dp:
            return dp[(r1, c1, r2, c2)]

        if r1 == N or c1 == N or r2 == N or c2 == N or grid[r1][c1] == -1 or grid[r2][c2] == -1:
            return float('-inf')

        if r1 == N - 1 and c1 == N - 1:
            return grid[r1][c1]

        if r2 == N - 1 and c2 == N - 1:
            return grid[r2][c2]

        ans = 0
        if r1 == r2 and c1 == c2:
            ans += grid[r1][c1]
        else:
            ans += grid[r1][c1] + grid[r2][c2]

        ans += max(solve(r1 + 1, c1, r2 + 1, c2),
                   solve(r1 + 1, c1, r2, c2 + 1),
                   solve(r1, c1 + 1, r2 + 1, c2),
                   solve(r1, c1 + 1, r2, c2 + 1))

        dp[(r1, c1, r2, c2)] = ans
        return ans

    result = solve(0, 0, 0, 0)
    return max(0, result)
